import React from "react";
import axios from "axios";

const Dashboard = () => {
  const [inspectors, setInspectors] = useState([]);
  const [newInspector, setNewInspector] = useState({
    name: "",
    department: "",
  });
  const [editingInspector, setEditingInspector] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchInspectors();
  }, []);

  const fetchInspectors = async () => {
    try {
      const response = await axios.get("http://localhost:5001/api/inspectors");
      setInspectors(response.data);
    } catch (error) {
      console.error("Error fetching inspectors:", error);
      setError("Failed to load inspectors");
    }
  };

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="kpis">
        <div className="kpi">
          <h1>$100,000</h1>
          <p>Total Sales</p>
        </div>
        <div className="kpi">
          <h1>250</h1>
          <p>Total Inspections</p>
        </div>
        <div className="kpi">
          <h1>150</h1>
          <p>Active Users</p>
        </div>
        <div className="kpi">
          <h1>150</h1>
          <p>Active Users</p>
        </div>
      </div>
      {/* Summary table */}
      <div className="inspectors-list">
        <h3>Current Inspectors</h3>
        {error && <div className="error-message">{error}</div>}
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Inspector ID</th>
                <th>Department</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {inspectors.map((inspector) => (
                <tr
                  key={inspector._id}
                  className={!inspector.active ? "inactive" : ""}
                >
                  <td>{inspector.name}</td>
                  <td>{inspector.inspectorId}</td>
                  <td>{inspector.department}</td>
                  <td>{inspector.active}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
